// NiceChunk switch controls LED + motor demo
// Wire it like this:
// VCC -> Switch A
// Switch B -> D2
// D13 -> LED signal
// LED GND -> GND
// D9 -> Motor +
// Motor - -> GND
const int switchPin = 2;
const int ledPin = 13;
const int motorPin = 9;

void setup() {
  pinMode(switchPin, INPUT);
  pinMode(ledPin, OUTPUT);
  pinMode(motorPin, OUTPUT);
}

void loop() {
  const bool enabled = digitalRead(switchPin) == HIGH;
  digitalWrite(ledPin, enabled ? HIGH : LOW);
  digitalWrite(motorPin, enabled ? HIGH : LOW);
  delay(10);
}
